let lastSort = { index: null, direction: 'asc' }; // direction: 'asc' | 'desc'
let lastFetchParams = { aarsem: null, fakultet: null };

// Tallkolonner (bruk samme som du har)
const tallKolonner = [
  "total_referanser_rapporteringspliktig",
  "antall_bolket",
