  // Tilpass endpoint-navn:
  // ex: POST /kopinor/refresh?aarsem=...&fakultet=...
  try {
    const { aarsem, fakultet } = lastFetchParams;
    const refreshEndpoint = `kopinor/refresh?aarsem=${encodeURIComponent(aarsem)}&fakultet=${encodeURIComponent(fakultet)}`;
    const refreshUrl = `/proxy.php?endpoint=${encodeURIComponent(refreshEndpoint)}`;

    // Hvis du vil: await fetch(refreshUrl, { method: 'POST' });
