    await fetch(refreshUrl);

  } catch (e) {
    // Ikke stopp; vi kan fortsatt prøve å hente data på nytt
  }

  // 2) hent nye data og oppdater kun tbody, behold sortering
  await hentOgRenderTabell({ ...lastFetchParams, fullRebuild: false });
}

async function hentOgRenderTabell({ aarsem, fakultet, fullRebuild }) {
  const endpoint = `kopinor/statistikk?aarsem=${encodeURIComponent(aarsem)}&fakultet=${encodeURIComponent(fakultet)}`;
  const url = `/proxy.php?endpoint=${encodeURIComponent(endpoint)}`;

  const resp = await fetch(url);
  if (!resp.ok) throw new Error("Feil ved henting av data");
  const data = await resp.json();

  if (!Array.isArray(data) || data.length === 0) {
    document.getElementById('tabellContainer').innerHTML = `<div class="alert alert-warning">Ingen data funnet.</div>`;
    return;
  }

  if (fullRebuild || !document.getElementById('resultatTabell')) {
    // Bygg hele tabellen første gang
    renderFullTable(data);
    initSortTracking();
  } else {
    // Senere: oppdater bare tbody
    updateTbodyOnly(data);
  }

  // Rebind detaljknapper (fordi vi bytter tbody-innhold)
  leggTilDetaljKnappEvent();

  // Re-apply forrige sort
  reapplyLastSort();
}

function renderFullTable(data) {
  let thead = `<thead><tr>`;
  Object.keys(data[0]).forEach(key => {
    if (tallKolonner.includes(key)) {
      thead += `<th data-sort-method="number">${key}</th>`;
    } else {
      thead += `<th>${key}</th>`;
    }
  });
  thead += `<th>Detaljer</th></tr></thead>`;

  const tbodyHtml = buildTbodyHtml(data);

  document.getElementById('tabellContainer').innerHTML = `
    <div class="table-responsive w-100">
      <table class="table table-striped table-bordered" id="resultatTabell" style="width: 100%;">
        ${thead}
        ${tbodyHtml}
      </table>
    </div>
  `;

  // Init Tablesort kun én gang per tabell
  tableSortInstance = new Tablesort(document.getElementById('resultatTabell'));
