function updateTbodyOnly(data) {
  const table = document.getElementById('resultatTabell');
  const oldTbody = table.querySelector('tbody');
  const newTbodyHtml = buildTbodyHtml(data);

  // Bytt bare tbody (minimerer “flimmer” og bevarer header/state bedre)
  const tmp = document.createElement('div');
  tmp.innerHTML = `<table>${newTbodyHtml}</table>`;
  const newTbody = tmp.querySelector('tbody');

  oldTbody.replaceWith(newTbody);
}

function buildTbodyHtml(data) {
  let tbody = '<tbody>';
  data.forEach(rad => {
    tbody += '<tr>';
    Object.entries(rad).forEach(([key, verdi]) => {
      if (tallKolonner.includes(key)) {
        const tallverdi = verdi !== null && verdi !== "" ? Number(verdi) : "";
        tbody += `<td data-sort="${tallverdi}">${tallverdi}</td>`;
      } else {
        tbody += `<td>${verdi !== null ? verdi : ''}</td>`;
      }
    });
    tbody += `<td><button class="btn btn-sm btn-outline-primary vis-detaljer-knapp" data-pensumliste-id="${rad.pensumliste_id}">Vis detaljer</button></td>`;
    tbody += '</tr>';
