```html name=refresh-in-place-by-kurskode.html
<script>
// bygger map fra kurskode -> radObj
function indexByKurskode(data) {
  const map = new Map();
  data.forEach(row => {
    if (row[KEY_FIELD] != null) map.set(String(row[KEY_FIELD]), row);
  });
  return map;
}

function updateTableInPlace(data) {
  const table = document.getElementById('resultatTabell');
  if (!table) return;

  const headers = Array.from(table.querySelectorAll('thead th')).map(th => th.textContent.trim());
  // headers inkluderer også "Detaljer" på slutten i din kode – den må vi hoppe over
  const hasDetaljer = headers[headers.length - 1] === "Detaljer";

  const byKey = indexByKurskode(data);

  const rows = Array.from(table.querySelectorAll('tbody tr'));

  rows.forEach(tr => {
    const kurskode = tr.dataset.kurskode;
    if (!kurskode) return;

    const newRow = byKey.get(String(kurskode));
    if (!newRow) {
      // valgfritt: marker at den ikke finnes lenger
      tr.classList.add('table-warning');
      return;
    } else {
      tr.classList.remove('table-warning');
    }

    const tds = Array.from(tr.querySelectorAll('td'));

    // oppdater alle celler som matcher header keys
    for (let i = 0; i < headers.length; i++) {
      const colName = headers[i];
      if (hasDetaljer && colName === "Detaljer") continue;

      const td = tds[i];
      if (!td) continue;

      const verdi = newRow[colName];

      // tallkolonner: behold data-sort riktig
      if (tallKolonner.includes(colName)) {
        const tallverdi = verdi !== null && verdi !== "" ? Number(verdi) : "";
        td.setAttribute('data-sort', tallverdi);
        td.textContent = tallverdi;
      } else {
        td.textContent = (verdi !== null && verdi !== undefined) ? verdi : "";
      }
    }

    // Oppdater pensumliste-id til detaljknappen hvis den kan endre seg
    const btn = tr.querySelector('.vis-detaljer-knapp');
    if (btn && newRow.pensumliste_id != null) {
      btn.dataset.pensumlisteId = newRow.pensumliste_id;
    }
  });

  // Hvis du vil: håndter nye kurskoder som ikke finnes i tabellen fra før:
  // enten ignorer, eller legg dem på slutten i frozen order.
}
</script>
```

